// Derive top stories from the analyst output and build a provider-neutral
// cover-image prompt in the shared premium house style. Mirrors
// config/intelligence/branding.json -> coverImage.styleDirectives.
const md = $json.message?.content || '';
const top = (md.split(/\n/).filter(l => /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l)).slice(0,4).join('; ')) || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs (flowing light, geometric grids, subtle infrastructure silhouettes, bokeh). NO text, NO logos, NO faces. Cinematic, restrained, high-end consultancy aesthetic.';
const prompt = `${style} Visual theme inspired by: ${top}.`;
const date = new Date().toISOString().slice(0,10);
return [{ json: { markdown: md, date, coverPrompt: prompt } }];

// Merge analyst Markdown + cover image into the shared branded base template
// (templates/report/intelligence-base.html.tpl, mounted at /templates).
const md = $('Build Cover Image Prompt').first().json.markdown || 'No data available for this period.';
const date = $('Build Cover Image Prompt').first().json.date || new Date().toISOString().slice(0,10);
const coverUrl = $json?.data?.[0]?.url || '';
const formats = ($env.ENERGY_BRIEF_OUTPUT_FORMATS || 'html,pdf,email,archive').split(',');
const content = `<pre>${md.replace(/[&<>]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]))}</pre>`;
const html = `<!doctype html><meta charset=\"utf-8\"><title>Daily Energy Intelligence Brief — ${date}</title>`+
  `<div style=\"font-family:Georgia,serif\"><div style=\"background:#0A1A2F;color:#E7C76A;padding:18px\">JARVIS INTELLIGENCE — Daily Energy Intelligence Brief — ${date}</div>`+
  (coverUrl?`<img src=\"${coverUrl}\" style=\"width:100%;max-height:280px;object-fit:cover\"/>`:'')+
  `<div style=\"padding:16px\">${content}</div></div>`;
return [{ json: { date, markdown: md, html, coverUrl, formats, product: 'energy-intelligence' } }];
